import * as t from "io-ts";
import { BaseIntent, BaseIntentWithAmount } from "./baseIntent";
import { intentTypes } from "./intentType";

/**
 * @title Bridge Funds Intent
 * Intent for bridging assets across chains or protocols
 *
 * The amount.symbol field identifies the asset to bridge (e.g., "ETH", "USDC")
 * The amount.value specifies how much to bridge
 */
export const BaseBridgeFundsIntent = t.intersection([
  BaseIntent,
  BaseIntentWithAmount, // Provides amount field with value + symbol (asset identifier)
  t.type({
    intentType: intentTypes.bridgeFunds,
  }),
]);

export type BaseBridgeFundsIntent = t.TypeOf<typeof BaseBridgeFundsIntent>;
